// Récupère hash + action depuis la query string et valide.
// action doit être 'selected' ou 'ignored' (cf. contrainte offers.status).
const q = $input.first().json.query || {};
const hash = String(q.hash || '').trim();
const action = String(q.action || '').trim();
if (!hash) throw new Error('hash manquant');
if (!['selected', 'ignored'].includes(action)) {
  throw new Error(`action invalide: ${action} (attendu selected|ignored)`);
}
return [{ json: { hash, action } }];
